import { useEffect, useState } from "react";
import api from "../api";

const money = n => (Number(n||0)).toLocaleString("vi-VN")+" ₫";

export default function Contracts() {
    const [rows, setRows] = useState([]);
    const [customers, setCustomers] = useState([]);
    const [form, setForm] = useState({
        code: "", customerId: "", totalAmount: "", signedDate: "", dueDate: "", contractType: "CONSTRUCTION", status: "IN_PROGRESS"
    });
    const [saving, setSaving] = useState(false);
    const [loading, setLoading] = useState(true);

    const load = async () => {
        setLoading(true);
        try {
            const [cts, cus] = await Promise.all([
                api.get("/api/contracts"),
                api.get("/api/customers"),
            ]);
            setRows(cts.data || []);
            setCustomers(cus.data || []);
            if (!form.customerId && cus.data?.length) setForm(s=>({...s, customerId: cus.data[0].id}));
        } finally {
            setLoading(false);
        }
    };
    useEffect(()=>{ load(); },[]);

    const save = async (e) => {
        e.preventDefault();
        setSaving(true);
        try {
            await api.post("/api/contracts", {
                title: form.code, // nếu backend cần title
                code: form.code,
                customerId: Number(form.customerId),
                totalAmount: Number(form.totalAmount),
                signedDate: form.signedDate,
                dueDate: form.dueDate,
                contractType: form.contractType,
                status: form.status
            });
            setForm(s=>({...s, code:"", totalAmount:"", signedDate:"", dueDate:""}));
            await load();
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-semibold">Hợp đồng</h2>
                    <p className="text-sm text-slate-500">Theo dõi mã, loại, giá trị và trạng thái</p>
                </div>
            </div>

            <form onSubmit={save} className="bg-white rounded-2xl border border-indigo-100 shadow p-4 grid grid-cols-1 md:grid-cols-6 gap-3">
                <input className="px-3 py-2 rounded-lg border" placeholder="Mã HĐ" value={form.code} onChange={e=>setForm(s=>({...s,code:e.target.value}))}/>
                <select className="px-3 py-2 rounded-lg border" value={form.customerId} onChange={e=>setForm(s=>({...s,customerId:e.target.value}))}>
                    {customers.map(c=>(<option key={c.id} value={c.id}>{c.name}</option>))}
                </select>
                <input type="number" className="px-3 py-2 rounded-lg border" placeholder="Giá trị" value={form.totalAmount} onChange={e=>setForm(s=>({...s,totalAmount:e.target.value}))}/>
                <input type="date" className="px-3 py-2 rounded-lg border" value={form.signedDate} onChange={e=>setForm(s=>({...s,signedDate:e.target.value}))}/>
                <input type="date" className="px-3 py-2 rounded-lg border" value={form.dueDate} onChange={e=>setForm(s=>({...s,dueDate:e.target.value}))}/>
                <button disabled={saving} className="px-3 py-2 rounded-lg bg-indigo-600 text-white">{saving?"Đang lưu...":"Thêm"}</button>
            </form>

            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
                {!loading && rows.map(c=>{
                    const customer = customers.find(x=>x.id===c.customerId);
                    return (
                        <div key={c.id} className="p-4 rounded-2xl bg-white border border-indigo-100 shadow">
                            <div className="flex items-start justify-between">
                                <div>
                                    <div className="font-semibold">{c.code || c.title}</div>
                                    <div className="text-sm text-slate-600">{customer?.name || "-"}</div>
                                    <div className="text-xs text-slate-500 mt-1">{(c.contractType||"").toString()} • Ký: {c.signedDate}</div>
                                </div>
                                <span className="px-2 py-0.5 rounded-full bg-amber-100 text-amber-700 text-xs">{c.status}</span>
                            </div>
                            <div className="grid grid-cols-3 gap-3 mt-3">
                                <div className="p-3 rounded-xl bg-indigo-50/50">
                                    <div className="text-xs text-slate-500">Giá trị</div>
                                    <div className="font-semibold">{money(c.totalAmount)}</div>
                                </div>
                                <div className="p-3 rounded-xl bg-emerald-50/50">
                                    <div className="text-xs text-slate-500">Đã thu</div>
                                    <div className="font-semibold">
                                        {/* nếu backend có tổng đã thu cho hợp đồng thì map vào */}
                                        {money(c.paidAmount || 0)}
                                    </div>
                                </div>
                                <div className="p-3 rounded-xl bg-amber-50/50">
                                    <div className="text-xs text-slate-500">Còn lại</div>
                                    <div className="font-semibold">{money((c.totalAmount||0) - (c.paidAmount||0))}</div>
                                </div>
                            </div>
                        </div>
                    );
                })}
                {loading && <div className="text-sm text-slate-500">Đang tải...</div>}
                {!loading && rows.length===0 && <div className="text-sm text-slate-500">Không có dữ liệu</div>}
            </div>
        </div>
    );
}
